parameters.jsCode:
const input = $input.first().json;

const resumeLatex = input.resume_latex || "";
const jobDescription = input.job_description || "";
const companyName = input.company_name || "";
const roleTitle = input.role_title || "";
const extraNotes = input.extra_notes || "";

if (!resumeLatex) {
  throw new Error("No resume_latex found from Resume form.");
}

if (!jobDescription) {
  throw new Error("No job_description found from Resume form.");
}

// -----------------------------
// Basic helpers
// -----------------------------
function normalize(value) {
  return String(value || "")
    .replace(/\\href\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textcolor\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textbf\{([^{}]*)\}/g, "$1")
    .replace(/\\textit\{([^{}]*)\}/g, "$1")
    .replace(/\\texttt\{([^{}]*)\}/g, "$1")
    .replace(/\\small\{([^{}]*)\}/g, "$1")
    .replace(/\\fa[A-Za-z]+/g, "")
    .replace(/[{}\\]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeKey(value) {
  return normalize(value)
    .toLowerCase()
    .replace(/[^a-z0-9+#./ -]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function slugify(value) {
  return normalizeKey(value)
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 60);
}

function escapeRegex(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function extractBlockBetweenSections(latex, startSection, endRegex) {
  const startRegex = new RegExp(`\\\\section\\{${escapeRegex(startSection)}\\}`, "i");
  const startMatch = latex.match(startRegex);

  if (!startMatch) return "";

  const afterStart = latex.slice(startMatch.index + startMatch[0].length);
  const endMatch = afterStart.match(endRegex);
  const endIndex = endMatch ? endMatch.index : afterStart.length;

  return afterStart.slice(0, endIndex);
}

function keywordSet(value) {
  const stopWords = new Set([
    "the", "and", "for", "with", "you", "your", "our", "are", "this", "that",
    "from", "will", "work", "role", "team", "have", "has", "using", "used",
    "into", "about", "their", "they", "them", "what", "where", "when", "who",
    "can", "all", "any", "more", "such", "etc", "was", "were", "been", "being",
    "to", "of", "in", "on", "as", "by", "an", "or", "at", "is", "it"
  ]);

  return new Set(
    normalizeKey(value)
      .split(/[^a-z0-9+#./-]+/)
      .map((word) => word.trim())
      .filter((word) => word.length >= 3 && !stopWords.has(word))
  );
}

function extractSummary(latex) {
  const summaryBlock = extractBlockBetweenSections(
    latex,
    "Summary",
    /\\section\{Skills\}|\\section\{Experience\}|\\section\{Education\}|\\section\{Projects\}|\\end\{document\}/i
  );

  return normalize(summaryBlock).slice(0, 900);
}

function extractSkillsBlock(latex) {
  const skillsBlock = extractBlockBetweenSections(
    latex,
    "Skills",
    /\\section\{Experience\}|\\section\{Education\}|\\section\{Projects\}|\\section\{Certifications\}|\\end\{document\}/i
  );

  return normalize(skillsBlock).slice(0, 1600);
}

// -----------------------------
// Resume section extraction
// -----------------------------
function extractSectionEntries(block, type) {
  const entries = [];
  const headingRegex = /\\headingBf\{([^{}]+)\}(?:\{([^{}]*)\})?/g;
  const matches = [...block.matchAll(headingRegex)];

  for (let i = 0; i < matches.length; i++) {
    const current = matches[i];
    const next = matches[i + 1];

    const heading = normalize(current[1]);
    const sectionId = `${type}_${slugify(heading)}`;

    const startIndex = current.index;
    const endIndex = next ? next.index : block.length;
    const sectionLatex = block.slice(startIndex, endIndex);

    const bullets = [];
    const bulletRegex =
      /\\item\s+([\s\S]*?)(?=\n\s*\\item|\n\s*\\end\{resume_list\}|\n\s*\\headingBf|\n\s*\\section|$)/g;

    let bulletMatch;
    let bulletCounter = 1;

    while ((bulletMatch = bulletRegex.exec(sectionLatex)) !== null) {
      const rawBullet = String(bulletMatch[1] || "");

      if (rawBullet.trim().startsWith("%")) continue;

      const bullet = normalize(rawBullet);

      if (bullet) {
        bullets.push({
          bullet_id: `${sectionId}_b${bulletCounter}`,
          text: bullet,
        });
        bulletCounter++;
      }
    }

    if (heading && bullets.length) {
      entries.push({
        section_id: sectionId,
        section: heading,
        type,
        bullets: bullets.slice(0, 8),
      });
    }
  }

  return entries;
}

function detectRoleFocus(jdText, roleText) {
  const text = `${jdText} ${roleText}`.toLowerCase();

  const scores = {
    frontend: 0,
    backend: 0,
    devops: 0,
    data: 0,
    testing: 0,
    support: 0,
  };

  const signals = {
    frontend: [
      "react", "next.js", "typescript", "javascript", "frontend", "front-end",
      "ui", "component", "accessibility", "a11y", "css", "html", "redux",
      "vue", "angular", "design system", "user interface"
    ],
    backend: [
      "backend", "back-end", "api", "apis", "rest", "graphql", "microservices",
      "node", "express", "django", "spring", "spring boot", "java", "python",
      "sql", "postgresql", "database", "server"
    ],
    devops: [
      "docker", "kubernetes", "terraform", "ci/cd", "cicd", "jenkins", "cloud",
      "aws", "azure", "gcp", "deployment", "infrastructure", "devops",
      "monitoring", "observability", "pipeline"
    ],
    data: [
      "data", "analytics", "dashboard", "reporting", "etl", "pipeline",
      "powerbi", "power bi", "bigquery", "sql", "warehouse", "metrics"
    ],
    testing: [
      "testing", "unit test", "integration test", "e2e", "jest", "cypress",
      "junit", "mockito", "quality", "qa", "test automation"
    ],
    support: [
      "support", "incident", "operations", "troubleshooting", "debugging",
      "stakeholder", "documentation", "readiness", "deployment support"
    ],
  };

  for (const [category, words] of Object.entries(signals)) {
    for (const word of words) {
      if (text.includes(word)) scores[category] += 1;
    }
  }

  return Object.entries(scores)
    .sort((a, b) => b[1] - a[1])
    .filter(([, score]) => score > 0)
    .map(([category]) => category)
    .slice(0, 3)
    .join(", ") || "general software";
}

function scoreSection(section, jdSet, roleFocus) {
  const sectionText = `${section.section} ${section.type} ${section.bullets.map((b) => b.text).join(" ")}`;
  const sectionSet = keywordSet(sectionText);

  let score = 0;

  for (const word of sectionSet) {
    if (jdSet.has(word)) score += 2;
  }

  const text = sectionText.toLowerCase();

  const boosts = {
    frontend: ["react", "redux", "next.js", "typescript", "javascript", "frontend", "ui", "component"],
    backend: ["api", "apis", "rest", "microservices", "node", "express", "django", "spring", "sql", "postgresql"],
    devops: ["docker", "kubernetes", "terraform", "ci/cd", "cloud", "aws", "azure", "gcp", "deployment"],
    data: ["data", "dashboard", "analytics", "etl", "pipeline", "reporting", "powerbi", "bigquery"],
    testing: ["testing", "junit", "mockito", "jest", "cypress", "unit", "integration"],
    support: ["support", "incident", "operations", "debugging", "documentation", "readiness", "stakeholder"],
  };

  for (const focus of roleFocus.split(",").map((x) => x.trim())) {
    const words = boosts[focus] || [];

    for (const word of words) {
      if (text.includes(word)) score += 3;
    }
  }

  if (section.type === "experience") score += 3;

  return score;
}

function getAllowedTermsForSection(section) {
  const sectionText = `${section.section} ${section.bullets.map((b) => b.text).join(" ")}`;
  const words = [...keywordSet(sectionText)];

  const importantTerms = [
    "react", "redux", "next.js", "typescript", "javascript", "node.js", "node",
    "express", "express.js", "django", "python", "java", "spring boot", "spring",
    "rest", "restful", "api", "apis", "graphql", "postgresql", "mysql", "mongodb",
    "dynamodb", "mssql", "aws", "azure", "gcp", "docker", "kubernetes", "terraform",
    "jenkins", "gitlab", "ci/cd", "cloudformation", "cloudwatch", "sns", "sqs",
    "bigquery", "powerbi", "power bi", "excel", "dashboards", "jira", "agile",
    "junit", "mockito", "jest", "cypress", "tobii", "hugging face", "opencv",
    "fasterrcnn", "ssd", "retinanet", "gke", "gdscript", "godot", "cosmosdb",
    "microservices", "cloud-native", "testing", "deployment", "debugging"
  ];

  const lowerText = sectionText.toLowerCase();

  for (const term of importantTerms) {
    if (lowerText.includes(term)) words.push(term);
  }

  return [...new Set(words)].slice(0, 80);
}

// -----------------------------
// Extract sections
// -----------------------------
const currentSummary = extractSummary(resumeLatex);
const skillsSummary = extractSkillsBlock(resumeLatex);

const experienceBlock = extractBlockBetweenSections(
  resumeLatex,
  "Experience",
  /\\section\{Education\}|\\section\{Projects\}|\\section\{Skills\}|\\section\{Certifications\}|\\end\{document\}/i
);

const projectsBlock = extractBlockBetweenSections(
  resumeLatex,
  "Projects",
  /\\section\{Certifications\s*\\&\s*Contributions\}|\\section\{Certifications\}|\\section\{Education\}|\\section\{Skills\}|\\end\{document\}/i
);

const experienceSections = extractSectionEntries(experienceBlock, "experience");
const projectSections = extractSectionEntries(projectsBlock, "project");

let targetSections = [...experienceSections, ...projectSections];

if (!targetSections.length) {
  throw new Error("Could not extract Experience or Project sections from resume LaTeX.");
}

// -----------------------------
// Select target sections
// -----------------------------
const safeJobDescription = String(jobDescription).slice(0, 4000);
const safeExtraNotes = String(extraNotes).slice(0, 900);
const jdSet = keywordSet(safeJobDescription);
const roleFocus = detectRoleFocus(safeJobDescription, roleTitle);

targetSections = targetSections
  .map((section) => ({
    ...section,
    allowed_terms: getAllowedTermsForSection(section),
    relevance_score: scoreSection(section, jdSet, roleFocus),
  }))
  .sort((a, b) => b.relevance_score - a.relevance_score)
  .slice(0, 5);

const targetSectionText = targetSections
  .map((item, index) => {
    const bulletText = item.bullets
      .map((bullet, bulletIndex) => {
        return `${bulletIndex + 1}. bullet_id: ${bullet.bullet_id}\ntext: ${bullet.text}`;
      })
      .join("\n");

    return `${index + 1}. section_id: ${item.section_id}
section: ${item.section}
type: ${item.type}
relevance_score: ${item.relevance_score}
allowed_terms_for_this_section:
${item.allowed_terms.join(", ")}
bullets:
${bulletText}`;
  })
  .join("\n\n");

// -----------------------------
// Prompt
// -----------------------------
const prompt = `
You are tailoring my LaTeX resume to a job description.

Return ONLY one valid JSON object.
No markdown.
No code fences.
No explanations.
No LaTeX commands inside bullet text.
Do not write anything before or after the JSON.

JSON shape:
{
  "summary": "",
  "role_focus": "",
  "updated_summary": "",
  "bold_keywords": [],
  "sections": [
    {
      "section_id": "exact section_id from input",
      "section": "exact section name from input",
      "type": "experience or project",
      "rewrite_points": [
        {
          "bullet_id": "exact bullet_id from input",
          "old_text": "exact existing bullet text from input",
          "new_text": "improved version of the same bullet",
          "reason": "why this rewrite is stronger for the job"
        }
      ],
      "comment_out": [
        {
          "bullet_id": "exact bullet_id from input",
          "old_text": "exact existing bullet text from input",
          "reason": "why this bullet is less relevant"
        }
      ]
    }
  ]
}

COMPANY:
${companyName}

ROLE:
${roleTitle}

ROLE FOCUS DETECTED:
${roleFocus}

JOB DESCRIPTION:
${safeJobDescription}

EXTRA NOTES:
${safeExtraNotes}

CURRENT SUMMARY:
${currentSummary}

CURRENT SKILLS:
${skillsSummary}

TARGET SECTIONS:
${targetSectionText}

TASK:
Tailor the resume safely for this job description.

VERY STRICT SAFETY RULES:
- Do not invent tools, metrics, dates, employers, projects, responsibilities, leadership, or achievements.
- Do not move experience between sections.
- Do not borrow a bullet from another job or project.
- Use section_id exactly as provided.
- Use bullet_id exactly as provided.
- Every old_text must exactly match the bullet text for that bullet_id.
- Every new_text must be a stronger version of old_text only.
- new_text may only use facts, tools, actions, and achievements already present in old_text or in allowed_terms_for_this_section.
- If a JD keyword is not supported by that exact section, do not force it into that section.
- Do not add completely new bullets.
- Do not add new metrics.
- Do not use em dash.
- Do not exaggerate seniority.
- Keep each new_text under 28 words.
- Preserve truth over keyword stuffing.

OUTPUT RULES:
- updated_summary must be 1 to 2 sentences only.
- updated_summary must use only facts from the resume summary, skills, and selected sections.
- bold_keywords must contain 8 to 15 short exact keywords from the resume or JD.
- Include 3 to 5 sections.
- For each section, rewrite exactly 1 existing bullet.
- For each section, comment_out is optional. Only include it if there is a clearly weaker bullet.
- Prefer improving bullets over deleting bullets.
- Use strong ATS wording but keep it natural.
`;

return [
  {
    json: {
      resume_latex: resumeLatex,
      job_description: jobDescription,
      company_name: companyName,
      role_title: roleTitle,
      extra_notes: extraNotes,
      current_summary: currentSummary,
      skills_summary: skillsSummary,
      target_sections: targetSections,
      role_focus: roleFocus,

      ollama_body: {
        model: "gemma3:latest",
        messages: [
          {
            role: "user",
            content: prompt,
          },
        ],
        stream: false,
        format: "json",
        options: {
          temperature: 0.05,
          num_predict: 2600,
          top_p: 0.55,
          repeat_penalty: 1.3,
          num_ctx: 8192,
        },
      },
    },
  },
];

const rawJson = $input.first().json;
const formData = $("Resume").first().json;

const originalResume = formData.resume_latex || rawJson.resume_latex || "";

if (!originalResume) {
  throw new Error("No resume_latex found from Resume form.");
}

// ─────────────────────────────────────────
// 1. Parse Ollama response
// ─────────────────────────────────────────
let responseText =
  rawJson.message?.content ||
  rawJson.response ||
  rawJson.text ||
  rawJson.output ||
  rawJson.content ||
  "";

if (typeof responseText === "object") {
  responseText = JSON.stringify(responseText);
}

if (!responseText) {
  throw new Error("No Ollama response found. Keys: " + Object.keys(rawJson).join(", "));
}

responseText = String(responseText)
  .replace(/```json/gi, "")
  .replace(/```latex/gi, "")
  .replace(/```tex/gi, "")
  .replace(/```/g, "")
  .trim();

const jsonStart = responseText.indexOf("{");
const jsonEnd = responseText.lastIndexOf("}");

if (jsonStart === -1 || jsonEnd === -1 || jsonEnd <= jsonStart) {
  throw new Error("Ollama did not return valid JSON. Got: " + responseText.slice(0, 700));
}

let edits;

try {
  edits = JSON.parse(responseText.slice(jsonStart, jsonEnd + 1));
} catch (err) {
  throw new Error("JSON parse failed: " + err.message + "\nRaw: " + responseText.slice(0, 900));
}

if (edits.suggestions && !edits.sections) {
  edits = edits.suggestions;
}

if (!Array.isArray(edits.sections)) {
  throw new Error("Ollama JSON missing sections array.");
}

// ─────────────────────────────────────────
// 2. Helpers
// ─────────────────────────────────────────
function slugify(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 70);
}

function escapeRegex(str) {
  return String(str || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function ensurePeriod(text) {
  const t = String(text || "").trim();
  return t && !/[.!?]$/.test(t) ? t + "." : t;
}

function escapeLatexText(text) {
  return String(text || "")
    .replace(/\\/g, "\\textbackslash{}")
    .replace(/&/g, "\\&")
    .replace(/%/g, "\\%")
    .replace(/#/g, "\\#")
    .replace(/_/g, "\\_")
    .replace(/\$/g, "\\$")
    .replace(/\{/g, "\\{")
    .replace(/\}/g, "\\}")
    .replace(/~/g, "\\textasciitilde{}")
    .replace(/\^/g, "\\textasciicircum{}");
}

function stripLatex(text) {
  return String(text || "")
    .replace(/\\href\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textcolor\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textbf\{([^{}]*)\}/g, "$1")
    .replace(/\\textit\{([^{}]*)\}/g, "$1")
    .replace(/\\texttt\{([^{}]*)\}/g, "$1")
    .replace(/\\small\{([^{}]*)\}/g, "$1")
    .replace(/\\fa[A-Za-z]+/g, "")
    .replace(/\\item\s*/gi, "")
    .replace(/[{}\\]/g, "")
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
}

function normalizePlain(text) {
  return stripLatex(text)
    .replace(/[^a-z0-9+#./ -]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function keywordSet(value) {
  const stopWords = new Set([
    "the", "and", "for", "with", "you", "your", "our", "are", "this", "that",
    "from", "will", "work", "role", "team", "have", "has", "using", "used",
    "into", "about", "their", "they", "them", "what", "where", "when", "who",
    "can", "all", "any", "more", "such", "etc", "was", "were", "been", "being",
    "to", "of", "in", "on", "as", "by", "an", "or", "at", "is", "it"
  ]);

  return new Set(
    normalizePlain(value)
      .split(/[^a-z0-9+#./-]+/)
      .map((word) => word.trim())
      .filter((word) => word.length >= 3 && !stopWords.has(word))
  );
}

function wordOverlapScore(a, b) {
  const setA = keywordSet(a);
  const setB = keywordSet(b);

  if (!setA.size || !setB.size) return 0;

  let common = 0;

  for (const word of setA) {
    if (setB.has(word)) common++;
  }

  return common / Math.min(setA.size, setB.size);
}

function cleanModelText(text) {
  return String(text || "")
    .replace(/^[-•–—]\s*/g, "")
    .replace(/^\\item\s*/g, "")
    .replace(/```/g, "")
    .replace(/—/g, "-")
    .replace(/–/g, "-")
    .replace(/\s+/g, " ")
    .trim();
}

function limitWords(text, maxWords = 32) {
  const words = String(text || "").trim().split(/\s+/).filter(Boolean);

  if (words.length <= maxWords) return text;

  return words.slice(0, maxWords).join(" ");
}

function getTechTerms(text) {
  const lower = normalizePlain(text);

  const terms = [
    "react", "redux", "next.js", "typescript", "javascript", "node.js", "node",
    "express", "express.js", "django", "python", "java", "spring boot", "spring",
    "rest", "restful", "api", "apis", "graphql", "postgresql", "mysql", "mongodb",
    "dynamodb", "mssql", "aws", "azure", "gcp", "docker", "kubernetes", "terraform",
    "jenkins", "gitlab", "ci/cd", "cloudformation", "cloudwatch", "sns", "sqs",
    "bigquery", "powerbi", "power bi", "excel", "dashboards", "jira", "agile",
    "junit", "mockito", "jest", "cypress", "tobii", "hugging face", "opencv",
    "fasterrcnn", "ssd", "retinanet", "gke", "gdscript", "godot", "cosmosdb",
    "microservices", "cloud-native", "testing", "deployment", "debugging",
    "arcgis", "stripe", "sofaboot", "maven", "cloud build"
  ];

  return terms.filter((term) => lower.includes(term));
}

function validateRewrite(oldText, newText, sectionBulletTexts) {
  const oldScore = wordOverlapScore(oldText, newText);
  const sectionScore = wordOverlapScore(sectionBulletTexts.join(" "), newText);

  if (oldScore < 0.22 && sectionScore < 0.28) {
    return {
      ok: false,
      reason: `Rewrite not close enough to old bullet or same section evidence. oldScore=${oldScore.toFixed(2)}, sectionScore=${sectionScore.toFixed(2)}`,
    };
  }

  const sectionText = sectionBulletTexts.join(" ");
  const sectionTerms = new Set(getTechTerms(sectionText));
  const oldTerms = new Set(getTechTerms(oldText));
  const newTerms = getTechTerms(newText);

  const unsupportedTerms = newTerms.filter((term) => {
    return !sectionTerms.has(term) && !oldTerms.has(term);
  });

  if (unsupportedTerms.length > 0) {
    return {
      ok: false,
      reason: `Rewrite introduced unsupported terms for this section: ${unsupportedTerms.join(", ")}`,
    };
  }

  const metricPattern = /\b\d+(\.\d+)?\s*(%|percent|x|times|ms|sec|seconds|min|minutes|hours|days|users|requests|uptime|coverage)\b/i;
  const newHasMetric = metricPattern.test(newText);
  const oldOrSectionHasMetric = metricPattern.test(oldText) || metricPattern.test(sectionText);

  if (newHasMetric && !oldOrSectionHasMetric) {
    return {
      ok: false,
      reason: "Rewrite introduced a new metric not supported by the old bullet or section.",
    };
  }

  const seniorityRiskWords = ["led", "owned", "architected", "managed", "directed", "principal", "senior"];
  const oldLower = normalizePlain(oldText);
  const sectionLower = normalizePlain(sectionText);
  const newLower = normalizePlain(newText);

  const riskyNewWords = seniorityRiskWords.filter((word) => {
    return newLower.includes(word) && !oldLower.includes(word) && !sectionLower.includes(word);
  });

  if (riskyNewWords.length > 0) {
    return {
      ok: false,
      reason: `Rewrite introduced unsupported seniority/ownership wording: ${riskyNewWords.join(", ")}`,
    };
  }

  return {
    ok: true,
    reason: `Validated against same section. oldScore=${oldScore.toFixed(2)}, sectionScore=${sectionScore.toFixed(2)}`,
  };
}

// ─────────────────────────────────────────
// 3. Read actual resume structure from LaTeX
// ─────────────────────────────────────────
function extractActualSectionsFromResume(resume) {
  const lines = resume.split("\n");
  const sections = [];

  function makeSectionId(type, heading) {
    return `${type}_${slugify(heading)}`;
  }

  let currentType = "";
  let insideRelevantArea = false;

  for (let i = 0; i < lines.length; i++) {
    const trimmed = lines[i].trim();

    if (/^\\section\{Experience\}/i.test(trimmed)) {
      currentType = "experience";
      insideRelevantArea = true;
      continue;
    }

    if (/^\\section\{Projects\}/i.test(trimmed)) {
      currentType = "project";
      insideRelevantArea = true;
      continue;
    }

    if (/^\\section\{Education\}/i.test(trimmed)) {
      insideRelevantArea = false;
      currentType = "";
      continue;
    }

    if (/^\\section\{Certifications/i.test(trimmed)) {
      insideRelevantArea = false;
      currentType = "";
      continue;
    }

    if (!insideRelevantArea || !trimmed.startsWith("\\headingBf")) continue;

    const firstArgMatch = lines[i].match(/\\headingBf\{([^{}]+)\}/);

    if (!firstArgMatch) continue;

    const heading = stripLatex(firstArgMatch[1]);
    const sectionName = firstArgMatch[1].replace(/\s+/g, " ").trim();
    const sectionId = makeSectionId(currentType, sectionName);

    let endIdx = lines.length;

    for (let j = i + 1; j < lines.length; j++) {
      const t = lines[j].trim();

      if (
        t.startsWith("\\headingBf") ||
        t.startsWith("\\section") ||
        t.startsWith("\\end{document}")
      ) {
        endIdx = j;
        break;
      }
    }

    const bullets = [];
    let bulletCounter = 1;

    for (let j = i; j < endIdx; j++) {
      const t = lines[j].trim();

      if (!t.startsWith("%") && /^\\item\s+/.test(t)) {
        bullets.push({
          bullet_id: `${sectionId}_b${bulletCounter}`,
          lineIdx: j,
          latex: lines[j],
          text: stripLatex(lines[j]),
          plain: normalizePlain(lines[j]),
        });

        bulletCounter++;
      }
    }

    sections.push({
      section_id: sectionId,
      section: sectionName,
      type: currentType,
      startIdx: i,
      endIdx,
      bullets,
    });
  }

  return sections;
}

function findSectionById(actualSections, sectionId, sectionName) {
  const wantedId = String(sectionId || "").trim();

  if (wantedId) {
    const exact = actualSections.find((s) => s.section_id === wantedId);
    if (exact) return exact;
  }

  const wantedName = normalizePlain(sectionName);

  if (!wantedName) return null;

  const exactName = actualSections.find((s) => normalizePlain(s.section) === wantedName);
  if (exactName) return exactName;

  let best = null;
  let bestScore = 0;

  for (const section of actualSections) {
    const score = wordOverlapScore(section.section, sectionName);

    if (score > bestScore) {
      best = section;
      bestScore = score;
    }
  }

  return bestScore >= 0.85 ? best : null;
}

function findBulletByIdOrText(section, bulletId, oldText) {
  const wantedId = String(bulletId || "").trim();

  if (wantedId) {
    const exact = section.bullets.find((b) => b.bullet_id === wantedId);

    if (exact) {
      return {
        bullet: exact,
        score: 1,
        matchType: "bullet_id",
      };
    }
  }

  const target = normalizePlain(oldText);

  if (!target) {
    return {
      bullet: null,
      score: 0,
      matchType: "none",
    };
  }

  for (const bullet of section.bullets) {
    if (bullet.plain === target) {
      return {
        bullet,
        score: 1,
        matchType: "exact_text",
      };
    }
  }

  let best = null;
  let bestScore = 0;

  for (const bullet of section.bullets) {
    const score = wordOverlapScore(bullet.text, oldText);

    if (score > bestScore) {
      best = bullet;
      bestScore = score;
    }
  }

  if (best && bestScore >= 0.7) {
    return {
      bullet: best,
      score: bestScore,
      matchType: "word_overlap",
    };
  }

  return {
    bullet: null,
    score: bestScore,
    matchType: "failed",
  };
}

// ─────────────────────────────────────────
// 4. Normalize model edits
// ─────────────────────────────────────────
edits.sections = edits.sections
  .filter((s) => s && (s.section_id || s.section))
  .slice(0, 5)
  .map((s) => {
    const rewritePoints = Array.isArray(s.rewrite_points)
      ? s.rewrite_points
          .slice(0, 1)
          .map((item) => ({
            bullet_id: String(item?.bullet_id || "").trim(),
            old_text: cleanModelText(item?.old_text || ""),
            new_text: cleanModelText(item?.new_text || ""),
            reason: String(item?.reason || "Better aligned to the job description").trim(),
          }))
          .filter((item) => item.old_text && item.new_text)
      : [];

    const commentOut = Array.isArray(s.comment_out)
      ? s.comment_out
          .slice(0, 1)
          .map((item) => ({
            bullet_id: String(item?.bullet_id || "").trim(),
            old_text: cleanModelText(item?.old_text || ""),
            reason: String(item?.reason || "Less relevant to this role").trim(),
          }))
          .filter((item) => item.old_text || item.bullet_id)
      : [];

    return {
      section_id: String(s.section_id || "").trim(),
      section: String(s.section || "").trim(),
      type: s.type === "project" ? "project" : "experience",
      rewrite_points: rewritePoints,
      comment_out: commentOut,
    };
  })
  .filter((s) => s.rewrite_points.length > 0);

if (!edits.sections.length) {
  throw new Error("No usable rewrite sections after normalization. Raw edits: " + JSON.stringify(edits));
}

// ─────────────────────────────────────────
// 5. Summary replacement
// ─────────────────────────────────────────
function replaceSummary(resume, updatedSummary) {
  const cleanSummary = cleanModelText(updatedSummary);

  if (!cleanSummary) {
    return {
      resume,
      changed: false,
      reason: "No updated_summary provided.",
    };
  }

  const safeSummary = ensurePeriod(escapeLatexText(limitWords(cleanSummary, 60)));

  const summaryRegex =
    /(\\section\{Summary\}\s*\n)([\s\S]*?)(\n\s*%[-]+%\s*\n\s*% Skills %|\n\s*\\section\{Skills\})/i;

  const match = resume.match(summaryRegex);

  if (!match) {
    return {
      resume,
      changed: false,
      reason: "Could not find Summary block safely.",
    };
  }

  const replacement = `${match[1]}${safeSummary}\n\n${match[3]}`;

  return {
    resume: resume.replace(summaryRegex, replacement),
    changed: true,
    reason: "Summary updated safely.",
  };
}

// ─────────────────────────────────────────
// 6. Apply edits
// ─────────────────────────────────────────
let updatedResume = originalResume;
const changeLog = [];

// PASS 0: Summary
const summaryResult = replaceSummary(updatedResume, edits.updated_summary || "");

updatedResume = summaryResult.resume;

changeLog.push({
  action: "update_summary",
  changed: summaryResult.changed,
  reason: summaryResult.reason,
  updated_summary: edits.updated_summary || "",
});

// PASS 1: Rewrite bullets safely
for (const sectionEdit of edits.sections) {
  const actualSections = extractActualSectionsFromResume(updatedResume);
  const section = findSectionById(actualSections, sectionEdit.section_id, sectionEdit.section);

  const rewrite = sectionEdit.rewrite_points[0];

  if (!section) {
    changeLog.push({
      action: "rewrite_point",
      changed: false,
      section_id: sectionEdit.section_id,
      section: sectionEdit.section,
      bullet_id: rewrite.bullet_id,
      old_text: rewrite.old_text,
      new_text: rewrite.new_text,
      reason: "Section not found safely by section_id or exact name.",
    });
    continue;
  }

  const match = findBulletByIdOrText(section, rewrite.bullet_id, rewrite.old_text);

  if (!match.bullet) {
    changeLog.push({
      action: "rewrite_point",
      changed: false,
      section_id: section.section_id,
      section: section.section,
      bullet_id: rewrite.bullet_id,
      old_text: rewrite.old_text,
      new_text: rewrite.new_text,
      reason: `Could not safely match bullet. Best score=${match.score.toFixed(2)}`,
    });
    continue;
  }

  const sectionBulletTexts = section.bullets.map((b) => b.text);
  const validation = validateRewrite(match.bullet.text, rewrite.new_text, sectionBulletTexts);

  if (!validation.ok) {
    changeLog.push({
      action: "rewrite_point",
      changed: false,
      section_id: section.section_id,
      section: section.section,
      bullet_id: rewrite.bullet_id,
      matched_line: match.bullet.latex.trim(),
      old_text: rewrite.old_text,
      new_text: rewrite.new_text,
      reason: validation.reason,
    });
    continue;
  }

  const safeNewText = ensurePeriod(escapeLatexText(limitWords(rewrite.new_text, 32)));
  const newLine = `\\item ${safeNewText}`;

  const lines = updatedResume.split("\n");

  lines[match.bullet.lineIdx] =
    `% OLD: ${match.bullet.latex.trim()}\n${newLine}`;

  updatedResume = lines.join("\n");

  changeLog.push({
    action: "rewrite_point",
    changed: true,
    section_id: section.section_id,
    section: section.section,
    bullet_id: match.bullet.bullet_id,
    old_text: rewrite.old_text,
    matched_line: match.bullet.latex.trim(),
    new_text: rewrite.new_text,
    match_score: match.score,
    match_type: match.matchType,
    validation: validation.reason,
    reason: rewrite.reason,
  });
}

// PASS 2: Optional comments
for (const sectionEdit of edits.sections) {
  if (!sectionEdit.comment_out || !sectionEdit.comment_out.length) continue;

  const comment = sectionEdit.comment_out[0];

  const actualSections = extractActualSectionsFromResume(updatedResume);
  const section = findSectionById(actualSections, sectionEdit.section_id, sectionEdit.section);

  if (!section) {
    changeLog.push({
      action: "comment_out",
      changed: false,
      section_id: sectionEdit.section_id,
      section: sectionEdit.section,
      bullet_id: comment.bullet_id,
      old_text: comment.old_text,
      reason: "Section not found safely by section_id or exact name.",
    });
    continue;
  }

  const match = findBulletByIdOrText(section, comment.bullet_id, comment.old_text);

  if (!match.bullet) {
    changeLog.push({
      action: "comment_out",
      changed: false,
      section_id: section.section_id,
      section: section.section,
      bullet_id: comment.bullet_id,
      old_text: comment.old_text,
      reason: `Could not safely match bullet to comment out. Best score=${match.score.toFixed(2)}`,
    });
    continue;
  }

  if (match.bullet.latex.trim().startsWith("% OLD:")) {
    changeLog.push({
      action: "comment_out",
      changed: false,
      section_id: section.section_id,
      section: section.section,
      bullet_id: match.bullet.bullet_id,
      old_text: comment.old_text,
      reason: "Skipped because this bullet was already rewritten.",
    });
    continue;
  }

  const lines = updatedResume.split("\n");

  lines[match.bullet.lineIdx] =
    `% REMOVED (${escapeLatexText(comment.reason)})\n% ${match.bullet.latex.trim()}`;

  updatedResume = lines.join("\n");

  changeLog.push({
    action: "comment_out",
    changed: true,
    section_id: section.section_id,
    section: section.section,
    bullet_id: match.bullet.bullet_id,
    old_text: comment.old_text,
    matched_line: match.bullet.latex.trim(),
    match_score: match.score,
    match_type: match.matchType,
    reason: comment.reason,
  });
}

// ─────────────────────────────────────────
// 7. Bold keywords safely
// ─────────────────────────────────────────
const fallbackKeywords = [
  "TypeScript",
  "JavaScript",
  "RESTful APIs",
  "REST APIs",
  "Node.js",
  "Express.js",
  "Spring Boot",
  "React",
  "Redux",
  "Next.js",
  "Vue.js",
  "Java",
  "Python",
  "Django",
  "PostgreSQL",
  "MongoDB",
  "DynamoDB",
  "SQL",
  "AWS",
  "Azure",
  "GCP",
  "Docker",
  "Kubernetes",
  "Terraform",
  "CI/CD",
  "Jenkins",
  "GitLab",
  "microservices",
  "cloud-native",
  "full-stack",
  "backend",
  "frontend",
  "DevOps",
  "testing",
  "deployment",
  "data pipeline",
  "dashboards",
  "PowerBI",
];

const boldKeywords = [
  ...new Set([
    ...(Array.isArray(edits.bold_keywords) ? edits.bold_keywords : []),
    ...fallbackKeywords,
  ]),
]
  .map((k) => String(k || "").trim())
  .filter(Boolean)
  .sort((a, b) => b.length - a.length);

function protectTextbf(line) {
  const parts = [];

  const protectedLine = line.replace(/\\textbf\{[^{}]*\}/g, (match) => {
    const token = `@@BOLD_${parts.length}@@`;
    parts.push(match);
    return token;
  });

  return {
    protectedLine,
    parts,
  };
}

function restoreTextbf(line, parts) {
  let result = line;

  parts.forEach((part, index) => {
    result = result.replace(`@@BOLD_${index}@@`, part);
  });

  return result;
}

function shouldBoldLine(line) {
  const trimmed = line.trim();

  if (!trimmed) return false;
  if (trimmed.startsWith("%")) return false;
  if (trimmed.startsWith("\\headingBf")) return false;
  if (trimmed.startsWith("\\headingIt")) return false;
  if (trimmed.startsWith("\\section")) return false;
  if (trimmed.startsWith("\\documentTitle")) return false;
  if (trimmed.startsWith("\\href")) return false;
  if (trimmed.startsWith("\\begin")) return false;
  if (trimmed.startsWith("\\end")) return false;

  return trimmed.startsWith("\\item") || (trimmed.length > 45 && trimmed.length < 800);
}

function applyBoldingToLine(line) {
  if (!shouldBoldLine(line)) return line;

  let { protectedLine, parts } = protectTextbf(line);
  let result = protectedLine;

  for (const kw of boldKeywords) {
    if (!kw) continue;

    const regex = new RegExp(
      `(^|[^A-Za-z0-9\\\\])(${escapeRegex(kw)})(?=[^A-Za-z0-9]|$)`,
      "gi"
    );

    result = result.replace(regex, (full, before, match) => {
      if (match.includes("@@BOLD_")) return full;
      return `${before}\\textbf{${match}}`;
    });
  }

  result = restoreTextbf(result, parts);

  result = result
    .replace(/\\textbf\{\\textbf\{([^{}]*)\}\}/g, "\\textbf{$1}")
    .replace(/\\textbf\{RESTful \\textbf\{APIs\}\}/g, "\\textbf{RESTful APIs}")
    .replace(/\\textbf\{REST \\textbf\{APIs\}\}/g, "\\textbf{REST APIs}")
    .replace(/\\textbf\{cloud-\\textbf\{native\}\}/g, "\\textbf{cloud-native}")
    .replace(/\\textbf\{full-\\textbf\{stack\}\}/g, "\\textbf{full-stack}");

  return result;
}

updatedResume = updatedResume
  .split("\n")
  .map((line) => applyBoldingToLine(line))
  .join("\n");

// ─────────────────────────────────────────
// 8. LaTeX safety cleanup
// ─────────────────────────────────────────
updatedResume = updatedResume
  .replace(/\\textbf\{\\textbf\{([^{}]*)\}\}/g, "\\textbf{$1}")
  .replace(/\\textbf\{RESTful \\textbf\{APIs\}\}/g, "\\textbf{RESTful APIs}")
  .replace(/\\textbf\{REST \\textbf\{APIs\}\}/g, "\\textbf{REST APIs}")
  .replace(/\\textbf\{cloud-\\textbf\{native\}\}/g, "\\textbf{cloud-native}")
  .replace(/\\textbf\{full-\\textbf\{stack\}\}/g, "\\textbf{full-stack}")
  .replace(/(-?\d+)px/g, "$1pt");

// ─────────────────────────────────────────
// 9. Output
// ─────────────────────────────────────────
const companyRaw = formData.company_name || rawJson.company_name || "company";
const roleRaw = formData.role_title || rawJson.role_title || "role";

const baseName = `resume_${slugify(companyRaw) || "company"}_${slugify(roleRaw) || "role"}`;
const workDir = `/home/node/.n8n-files/${baseName}`;

const successfulEdits = changeLog.filter((e) => e.changed);
const failedEdits = changeLog.filter((e) => !e.changed);

return [
  {
    json: {
      updated_resume_latex: updatedResume,
      resume_base64: Buffer.from(updatedResume, "utf8").toString("base64"),

      change_log: changeLog,
      change_log_base64: Buffer.from(
        JSON.stringify(
          {
            summary: edits.summary || "",
            role_focus: edits.role_focus || rawJson.role_focus || "",
            updated_summary: edits.updated_summary || "",
            sections_processed: edits.sections.length,
            successful_edits: successfulEdits.length,
            failed_edits: failedEdits.length,
            edits,
            changeLog,
            bold_keywords_used: boldKeywords,
          },
          null,
          2
        ),
        "utf8"
      ).toString("base64"),

      sections_found: edits.sections.map((s) => ({
        section_id: s.section_id,
        section: s.section,
      })),

      successful_edits: successfulEdits.length,
      failed_edits: failedEdits.length,
      failed_details: failedEdits,

      relevant_summary: edits.summary || "",
      role_focus: edits.role_focus || rawJson.role_focus || "",
      updated_summary: edits.updated_summary || "",
      bold_keywords: boldKeywords,

      work_dir: workDir,
      tex_path: `${workDir}/${baseName}.tex`,
      pdf_path: `${workDir}/${baseName}.pdf`,
      log_path: `${workDir}/${baseName}_changes.json`,
      tex_file_name: `${baseName}.tex`,
      pdf_file_name: `${baseName}.pdf`,
      log_file_name: `${baseName}_changes.json`,
    },
  },
];

const stdout = $input.first().json.stdout || "";
const stderr = $input.first().json.stderr || "";

const texPath = stdout.trim();

if (!texPath || texPath.includes("ERROR")) {
  throw new Error("No TEX file found. stdout: " + stdout + " stderr: " + stderr);
}

const fileName = texPath.split("/").pop();

return [
  {
    json: {
      tex_path: texPath,
      tex_file_name: fileName
    }
  }
];

const input = $input.first().json;

const fileTypeRaw = input.file_type || "";
const companyRaw = input.company_name || "";
const roleRaw = input.role_title || "";

if (!fileTypeRaw) {
  throw new Error("File Type is required.");
}

if (!companyRaw) {
  throw new Error("Company Name is required.");
}

if (!roleRaw) {
  throw new Error("Role Title is required.");
}

function slugify(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 70);
}

const fileType = slugify(fileTypeRaw);
const company = slugify(companyRaw);
const role = slugify(roleRaw);

let prefix = "";

if (fileType === "resume") {
  prefix = "resume";
} else if (fileType === "cover_letter") {
  prefix = "cover_letter";
} else {
  throw new Error("Invalid file type. Use resume or cover_letter.");
}

const baseName = `${prefix}_${company}_${role}`;
const texFileName = `${baseName}.tex`;

return [
  {
    json: {
      file_type: fileType,
      company_name: companyRaw,
      role_title: roleRaw,
      base_name: baseName,
      tex_file_name: texFileName
    }
  }
];
